import './Timeline.scss';

import { classNames } from ':helpers/classnames';
import { useDeviceSize } from ':helpers/use-device-size';
import type { FC } from 'react';
import React, { useMemo } from 'react';

import type { TimelineProps } from './Timeline.types';
import { TimelineHorizontal } from './TimelineHorizontal';
import { TimelineVertical } from './TimelineVertical';

export const Timeline: FC<TimelineProps> = ({
	direction = 'vertical',
	steps = [],
	activeStepId,
	onCollapse,
	collapsed = false,
	collapsable = false,
	completed = false,
	className,
}) => {
	const { isExtraSmallDevice } = useDeviceSize();

	const _direction = isExtraSmallDevice ? 'vertical' : direction;

	if (isExtraSmallDevice && direction === 'horizontal') {
		console.debug('[DSB-Timeline] Для мобильного компонента Timeline используется только direction="vertical"');
	}

	const stepsLength = steps.length;

	/** Возвращает индекс активного шага по id:string шага. */
	const activeStepIndex: number = useMemo(
		() => steps.findIndex(step => step.id === activeStepId),
		[steps, activeStepId],
	);

	if (!stepsLength) {
		return null;
	}

	return (
		<ol role="list" data-testid="Timeline" className={classNames('dsb_timeline', className)}>
			{_direction === 'vertical' && (
				<TimelineVertical
					steps={steps}
					collapsable={collapsable}
					collapsed={collapsed}
					onCollapse={onCollapse}
					completed={completed}
					activeStepIndex={activeStepIndex}
				/>
			)}

			{_direction === 'horizontal' && (
				<TimelineHorizontal steps={steps} activeStepIndex={activeStepIndex} completed={completed} />
			)}
		</ol>
	);
};
